input_region.addEventListener("input", (e) => {
    clearThis(input_city)
    for (let i = 0; i < regionsCold.length; i++) {
        if (regionsCold[i].childNodes[0].nodeValue === e.target.value) {
            input_city.innerHTML += '<option value="'+ elementsCold[i].childNodes[0].nodeValue +'">' + elementsCold[i].childNodes[0].nodeValue + '</option>';

        }
    }
    console.log("Ok")
})

input_city.addEventListener("click",(e) => {
    let current, currentWarm, currentYear, currentVaporPressure, currentMonthlyAmlitude

    //Cold air table filling
    for (let i = 0; i < elementsCold.length; i++) {
        if (elementsCold[i].childNodes[0].nodeValue === input_city.value) {
            current = elementsCold[i].nextElementSibling
            break
        }
    }

    for (let i = 0; i < 19; i++) {
        document.getElementsByClassName("climat-val-cold")[i].innerHTML = current.childNodes[0].nodeValue
        current = current.nextElementSibling
    }


    //Warm air table filling
    for (let i = 0; i < elementsWarm.length; i++) {
        if (elementsWarm[i].childNodes[0].nodeValue === input_city.value) {
            currentWarm = elementsWarm[i].nextElementSibling
            break
        }
    }

    for (let i = 0; i < 12; i++) {
        document.getElementsByClassName("climat-val")[i].innerHTML = currentWarm.childNodes[0].nodeValue
        currentWarm = currentWarm.nextElementSibling
    }


    //Year climate table filling
    for (let i = 0; i < elementsYearClimate.length; i++) {
        if (elementsYearClimate[i].childNodes[0].nodeValue === input_city.value) {
            currentYear = elementsYearClimate[i].nextElementSibling
            break
        }
    }

    for (let i = 0; i < 13; i++) {
        document.getElementsByClassName("yearClimate")[i].innerHTML = currentYear.childNodes[0].nodeValue
        currentYear = currentYear.nextElementSibling
    }


    //Vapor pressure table filling
    for (let i = 0; i < elementsVaporPressure.length; i++) {
        if (elementsVaporPressure[i].childNodes[0].nodeValue === input_city.value) {
            currentVaporPressure = elementsVaporPressure[i].nextElementSibling
            break
        }
    }

    for (let i = 0; i < 13; i++) {
        document.getElementsByClassName("vapor-pressure")[i].innerHTML = currentVaporPressure.childNodes[0].nodeValue
        currentVaporPressure = currentVaporPressure.nextElementSibling
    }


    //Monthly amplitude table filling
    for (let i = 0; i < elementsMonthlyAmplitude.length; i++) {
        if (elementsMonthlyAmplitude[i].childNodes[0].nodeValue === input_city.value) {
            currentMonthlyAmlitude = elementsMonthlyAmplitude[i].nextElementSibling
            break
        }
    }

    for (let i = 0; i < 24; i++) {
        document.getElementsByClassName("avg-month-amplitude")[i].innerHTML = currentMonthlyAmlitude.childNodes[0].nodeValue
        currentMonthlyAmlitude = currentMonthlyAmlitude.nextElementSibling
    }



    //Insert regions and cities names

    let newlist = document.getElementsByClassName("Region")
    console.log(newlist)
    // for (region in newlist) {
    //     region.innerHTML = input_region.value
    // }
    document.getElementById("City").innerHTML = input_city.value
    document.getElementById("city_").innerHTML = input_city.value

})

